True systems programming requires thinking about resource management, security, and lifecycle, even for a simple "Hello World". Both implementations below include strict HTTP method checking, basic security headers, and graceful shutdown handling—all without a single external dependency.

### 1. Node.js (`node:http`)

We use the built-in `node:http` module. We explicitly handle the HTTP methods, set headers to prevent MIME-sniffing, and trap OS signals to drain connections before exiting.

```javascript
// server.js
const http = require('node:http');

const PORT = process.env.PORT || 3000;

const server = http.createServer((req, res) => {
    // 1. Set baseline security headers
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('X-Frame-Options', 'DENY');
    res.setHeader('Content-Security-Policy', "default-src 'none'");

    // 2. Enforce strict method handling
    if (req.method !== 'GET') {
        res.writeHead(405, { 'Content-Type': 'text/plain' });
        res.end('405 Method Not Allowed\n');
        return;
    }

    // 3. Route handling
    if (req.url === '/') {
        res.writeHead(200, { 'Content-Type': 'text/plain' });
        res.end('Hello World\n');
    } else {
        res.writeHead(404, { 'Content-Type': 'text/plain' });
        res.end('404 Not Found\n');
    }
});

server.listen(PORT, () => {
    console.log(`Server listening on port ${PORT}`);
});

// 4. Graceful shutdown handling
const shutdown = (signal) => {
    console.log(`\nReceived ${signal}. Draining connections...`);
    server.close(() => {
        console.log('Server offline.');
        process.exit(0);
    });

    // Force exit if connections don't drain within 5 seconds
    setTimeout(() => {
        console.error('Forcing shutdown.');
        process.exit(1);
    }, 5000).unref();
};

process.on('SIGINT', () => shutdown('SIGINT'));
process.on('SIGTERM', () => shutdown('SIGTERM'));
```
**Run it:** `node server.js`

